package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

public class CSVFormatTest {

    @Test
    public void testWithDelimiter_ValidDelimiter() {
        // Given
        char delimiter = '|';
        CSVFormat csvFormat = createCSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        CSVFormat result = csvFormat.withDelimiter(delimiter);

        // Then
        assertEquals(delimiter, result.getDelimiter());
    }

    @Test
    public void testWithDelimiter_InvalidDelimiter() {
        // Given
        char delimiter = '\n';
        CSVFormat csvFormat = createCSVFormat(',', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            csvFormat.withDelimiter(delimiter);
        });

        // Then
        assertEquals("The delimiter cannot be a line break", exception.getMessage());
    }

    private CSVFormat createCSVFormat(char delimiter, Character quoteCharacter, QuoteMode quoteMode,
                                       Character commentMarker, Character escapeCharacter, boolean ignoreSurroundingSpaces,
                                       boolean ignoreEmptyLines, String recordSeparator, String nullString,
                                       Object[] headerComments, String[] header, boolean skipHeaderRecord,
                                       boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
                                       boolean trailingDelimiter) {
        try {
            Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                    Character.class, Character.class, boolean.class, boolean.class, String.class, String.class,
                    Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
            constructor.setAccessible(true);
            return constructor.newInstance(delimiter, quoteCharacter, quoteMode, commentMarker, escapeCharacter,
                    ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, headerComments,
                    header, skipHeaderRecord, allowMissingColumnNames, ignoreHeaderCase, trim, trailingDelimiter);
        } catch (NoSuchMethodException | InstantiationException | IllegalAccessException | InvocationTargetException e) {
            e.printStackTrace();
            return null;
        }
    }
}
